  ('promotion-660afcb0-moex-00149', 'promotion-660afcb0', 'promotion-660afcb0-moex-110-3a7b2121', 'sub-promotion-660afcb0-03', NULL, 'single_choice', '有關亞當斯（J.Adams）公平理論（equitytheory）之內涵，下列敘述何者錯誤？', '["公平理論主要在討論工作結果與工作投入的比率，當這個比率與他人相比而不相稱時，就會有 不公平的感受", "當不公平的原因在於本人的工作結果與投入的比率比他人低時，消除不公平的方式可以是增加 投入", "當人們感覺所得報酬與其努力之間有差距，而此差距是主觀感受的結果", "當原本感受到不公平的人出現「比上不足、比下有餘」的感覺時，是因為他改換了其他的比較 對象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:52+00:00", "source_pdf_sha1": "642c105f3438", "answer_pdf_sha1": "44597aef9ae9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "143", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
